head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.sUserClsCd = scwin.memJson.userClsCd || "";
scwin.sClntNo = scwin.memJson.clntNo || "";
scwin.sClntNm = scwin.memJson.clntNm || "";
scwin.sLobranCd = scwin.memJson.loUpperLobranCd || "";

scwin.v_wrkDt = ""; // 파라미터로 넘어오는 지시일자 (init 시 세팅)
scwin.v_vehclNoCd = "";
scwin.v_vehclNo = "";
scwin.v_odrNo = "";
scwin.wrkLobranCd = "";

scwin.g_chkScroll = false;
scwin.result = "";
scwin.pos_groupCode = 0;


scwin.onpageload = async function () {
    // 1. 파라미터 수신 (웹스퀘어 방식 $p.getParameter)
    scwin.v_wrkDt = $p.getParameter("wrkDt") || "";
    scwin.v_vehclNoCd = $p.getParameter("vehclNoCd") || "";
    scwin.v_vehclNo = $p.getParameter("vehclNo") || "";
    scwin.v_odrNo = $p.getParameter("odrNo") || "";
    scwin.wrkLobranCd = $p.getParameter("wrkLobranCd") || "";
    const codeOptions = [
        {
            method: "getLuxeComboData",
            param1: "NcallWorkImplementEBC",
            param2: "retriveLobran2CodeList",
            param3: ["1"],
            compID: "acb_logisticsBranch"
        }
    ];
    $c.data.setGauceUtil(codeOptions, scwin.callbackCodeOpt2);

    // 2. 공통코드 세팅
    // (LuxeCombo -> WebSquare SelectBox 세팅 로직 추가 필요 시 여기에 작성)
    // await $c.data.setCommonCode([...]);

    // 3. 초기화 로직 분기
    if (scwin.wrkLobranCd == "") {
        acb_logisticsBranch.setValue(scwin.sLobranCd);
        ed_dptTime.setValue("0800");

        if (scwin.v_wrkDt != "") {
            wrkDt.setValue(scwin.v_wrkDt);
            ed_vehclShortNo.setValue(scwin.v_vehclNoCd);
            ed_vehclNo.setValue(scwin.v_vehclNo);
            ed_odrNo.setValue(scwin.v_odrNo);

            scwin.f_Retrieve();
        } else {
            wrkDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
        }
        wrkDt.focus();
    } else {
        acb_logisticsBranch.setValue(scwin.wrkLobranCd);
        wrkDt.setValue(scwin.v_wrkDt);
        ed_odrNo.setValue(scwin.v_odrNo);
        scwin.f_Retrieve();
    }
};
scwin.callbackCodeOpt2 = function () {
   if(scwin.sLobranCd !== ""){
        acb_logisticsBranch.setValue(scwin.sLobranCd);
    }else{
        acb_logisticsBranch.setValue('0');
    }
}
scwin.f_Retrieve = function () {
    scwin.g_chkScroll = false;

    if (ed_odrNo.getValue() == "") {
        if (wrkDt.getValue().trim() == "") {
            $c.win.alert("오더번호를 입력하세요");
            return;
        }
        if (wrkDt.getValue().trim() == "" && vehclNo.getValue() == "") {
            $c.win.alert("지시일자와 차량번호를 입력하세요. 지시일자 + 차량번호로 조회해야 합니다");
            return;
        }
        if (wrkDt.getValue().trim() != "" && vehclNo.getValue() == "" && co_lc_transRsltsExistYn.getValue() == "") {
            $c.win.alert("차량번호나 출도착등록여부를  입력하세요.\n지시일자 +차량번호 혹은 지시일자+출도착등록여부로 조회해야 합니다");
            return;
        }
        if (wrkDt.getValue().trim() == "" && vehclNo.getValue() != "") {
            $c.win.alert("지시일자를 입력하세요");
            return;
        }
    } else {
        wrkDt.setValue("");
    }

    cheCnt.setValue("0");

    dma_retrieve.set("vehclNo", vehclNo.getValue());
    dma_retrieve.set("wrkDt", wrkDt.getValue().trim());
    dma_retrieve.set("odrNo", ed_odrNo.getValue());
    dma_retrieve.set("ctrtClntNo", ed_ctrtClntNo.getValue().trim());
    dma_retrieve.set("wrkLobranCd", co_lc_logisticsBranch.getValue());
    dma_retrieve.set("selfTransClntNo", ed_srchSelfTransCoCd.getValue());
    dma_retrieve.set("transRsltsExistYn", co_lc_transRsltsExistYn.getValue());
    dma_retrieve.set("clntMgntNo", ed_clntMgntNo.getValue());
    dma_retrieve.set("clntMgntList", scwin.result);

    $c.sbm.execute(sbm_retrieve);
};
scwin.f_Retrieve2 = function () {
    if (ed_odrNo.getValue() == "") {
        if (wrkDt.getValue().trim() == "") {
            $c.win.alert("오더번호를 입력하세요");
            return;
        }
        if (wrkDt.getValue().trim() == "" && ed_vehclShortNo.getValue() == "") {
            $c.win.alert("지시일자와 차량번호를 입력하세요. 지시일자 + 차량번호로 조회해야 합니다");
            return;
        }
        if (wrkDt.getValue().trim() != "" && ed_vehclShortNo.getValue() == "" && acb_transRsltsExistYn.getValue() == "") {
            $c.win.alert("차량번호나 출도착등록여부를  입력하세요.\n지시일자 +차량번호 혹은 지시일자+출도착등록여부로 조회해야 합니다");
            return;
        }
        if (wrkDt.getValue().trim() == "" && ed_vehclShortNo.getValue() != "") {
            $c.win.alert("지시일자를 입력하세요");
            return;
        }
    } else {
        wrkDt.setValue("");
    }

    // cheCnt.setValue("0");

    dma_retrieve2.set("wrkLobranCd", acb_logisticsBranch.getValue());
    dma_retrieve2.set("wrkDt", wrkDt.getValue().trim());
    dma_retrieve2.set("odrNo", ed_odrNo.getValue());
    dma_retrieve2.set("vehclNo", ed_vehclNo.getValue());
    dma_retrieve2.set("clntMgntNo", ed_clntMgntNo.getValue());
    dma_retrieve2.set("transRsltsExistYn", acb_transRsltsExistYn.getValue());
    dma_retrieve2.set("ctrtClntNo", ed_ctrtClntNo.getValue().trim());

    $c.sbm.execute(sbm_retrieve2);
};

scwin.f_Save = async function () {
    // 1. 변경된 데이터 체크
    if (ds_emp2.getModifiedIndex().length === 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    // 2. 출발일시 from ~ to 체크 및 Validation
    for (let i = 0; i < ds_emp2.getRowCount(); i++) {
        let dptDt = ds_emp2.getCellData(i, "dptDt");
        let dptHh = ds_emp2.getCellData(i, "dptHh");
        let arvDt = ds_emp2.getCellData(i, "arvDt");
        let arvHh = ds_emp2.getCellData(i, "arvHh");

        let stDtm = dptDt + dptHh;
        let endDtm = arvDt + arvHh;

        // 삭제행 패스 & 입출고 대상 삭제 금지
        if (ds_emp2.getRowStatus(i) === "D") {
            if (ds_emp2.getCellData(i, "ioDptWrkPlCd") == "1") {
                $c.win.alert("입출고 관리 대상이므로 삭제 못합니다.");
                return;
            }
            continue;
        }

        if (ds_emp2.getCellData(i, "ioArvWrkPlCd") == "0") {
            if (dptHh == "") {
                ds_emp2.setRowPosition(i);
                $c.win.alert("출발시간을 입력하세요");
                gr_emp2.setFocusedCell(i, "dptHh", true);
                return;
            }
            if (arvHh == "") {
                ds_emp2.setRowPosition(i);
                $c.win.alert("도착시간을 입력하세요");
                gr_emp2.setFocusedCell(i, "arvHh", true);
                return;
            }
            // if (!scwin.f_validDate(endDtm.trim(), "YYYYMMDDHHmm", "도착일자시간")) {
            //     gr_emp2.setFocusedCell(i, "arvDt", true);
            //     return;
            // }
        }

        if (dptDt != "" && dptHh != "" && arvDt != "" && arvHh != "") {
            if (!scwin.f_DifferBetweenDate(stDtm, endDtm)) {
                $c.gus.cfAlertMsg((i + 1) + "번째 데이타에서 시작일자가 종료일자 이전이어야 합니다.");
                return;
            }
        }

        if (dptDt.length > 0 && dptDt.length < 8) { $c.gus.cfAlertMsg("날짜형식이 올바르지 않습니다."); return; }
        if (arvDt.length > 0 && arvDt.length < 8) { $c.gus.cfAlertMsg("날짜형식이 올바르지 않습니다."); return; }
        if (dptHh.length > 0 && dptHh.length < 4) { $c.gus.cfAlertMsg("날짜형식이 올바르지 않습니다."); return; }
        if (arvHh.length > 0 && arvHh.length < 4) { $c.gus.cfAlertMsg("날짜형식이 올바르지 않습니다."); return; }

        // if (!scwin.f_validDate(stDtm.trim(), "YYYYMMDDHHmm", "출발일자시간")) {
        //     return;
        // }
    }

    // 3. 원본값 세팅
    scwin.isUpdate();

    // 4. 시간 체크 로직
    if (!scwin.hourCheck()) return;
    if (!scwin.hourNullCheck()) return;

    // 5. 컨펌 및 서브미션 실행
    let isConfirm = await $c.win.confirm(MSG_CM_CRM_001);
    if (isConfirm) {
        // 저장 시에도 조회조건(dma_retrieve) 세팅해서 같이 넘김
        dma_retrieve.set("vehclNo", ed_vehclNo.getValue());
        dma_retrieve.set("wrkDt", wrkDt.getValue().trim());
        dma_retrieve.set("odrNo", ed_odrNo.getValue());
        dma_retrieve.set("ctrtClntNo", ed_ctrtClntNo.getValue().trim());
        dma_retrieve.set("wrkLobranCd", acb_logisticsBranch.getValue());

        scwin.pos_groupCode = ds_emp.getRowPosition();
        for (var i = 0; i < ds_emp2.getRowCount(); i++) {
        }

        $c.sbm.execute(sbm_saveEmp);
    }
};

//-------------------------------------------------------------------------
// 일괄적용 201706
// odr_no, cntr_seq가 달라지면 새로운 오더로 인식
// 1) 출도착없을경우 8시-9시 10시-11시 ...
// 2) 있는경우 +1시간
//-------------------------------------------------------------------------
scwin.f_apply = function () {
    var dPtime = ed_dptTime.getValue();
    var valhh = parseInt(dPtime.substr(0, 2), 10);
    var valmm = dPtime.substr(2, 2).trim();
    var Dhr, Dmn, Ahr, Amn;
    var hh, mn;

    for (var row = 0; row < ds_emp2.getRowCount(); row++) {
        Dhr = parseInt(ds_emp2.getCellData(row, "dptHh").substr(0, 2), 10);
        Dmn = ds_emp2.getCellData(row, "dptHh").substr(2, 2);
        Ahr = parseInt(ds_emp2.getCellData(row, "arvHh").substr(0, 2), 10);
        Amn = ds_emp2.getCellData(row, "arvHh").substr(2, 2);
        //출발일시/도착일시가 없는게 있는경우만 진행하기
        if (isNaN(Dhr) || isNaN(Ahr)) {
            //odrNo cntrSeq 가 같은 앞 데이터가 있는 경우는 앞전 거+1시간 하기
            if (row > 0 &&
                (ds_emp2.getCellData(row - 1, "odrNo") == ds_emp2.getCellData(row, "odrNo")) &&
                (ds_emp2.getCellData(row - 1, "commSeq") == ds_emp2.getCellData(row, "commSeq"))) {
                // f_setData(row);
            }
            //새로운 odrNo&&cntrSeq인 경우  ed_dptTime의 값을 셋팅
            else {
                if (isNaN(Dhr)) {
                    hh = valhh; mn = valmm;
                } else {
                    hh = Dhr; mn = Dmn;
                }

                if (hh < 9) {
                    if (scwin.f_checkColValue(row, "dptHh")) ds_emp2.setCellData(row, "dptHh", "0" + hh + mn);
                    if (scwin.f_checkColValue(row, "arvHh")) ds_emp2.setCellData(row, "arvHh", "1800");
                } else {
                    if (scwin.f_checkColValue(row, "dptHh")) {
                        var hhh = String(hh);
                        if (hhh.length == 2) ds_emp2.setCellData(row, "dptHh", hh + mn);
                        else if (hhh.length == 1) ds_emp2.setCellData(row, "dptHh", "0" + hh + mn);
                        else { $c.win.alert("출발일시를 다시 입력하시기 바랍니다."); return; }
                    }
                    if (scwin.f_checkColValue(row, "arvHh")) ds_emp2.setCellData(row, "arvHh", "1800");
                }
            }
        }
    }
};

/**
 * method
 * @name f_setData
 * @description 앞데이터의 odrNo cntrSeq 가 현재꺼랑 같은경우  앞전 거+1시간 하기
 */
scwin.f_setData = function (row, prevRowObj, rowObj) {
    let dpt = $c.num.parseInt(rowObj.dptHh.substring(0, 2));
    let avr = $c.num.parseInt(rowObj.arvHh.substring(0, 2));
    if (scwin.f_checkColValue(row, rowObj, "dptHh")) {
        if (dpt == "" || isNaN(dpt)) {
            let DdtYMD = prevRowObj.arvDt;
            let Ahr = $c.num.parseInt(prevRowObj.arvHh.substring(0, 2));
            let AMn = prevRowObj.arvHh.substring(2, 4);
            if (Ahr >= 0 && Ahr < 23) {
                if (Ahr < 9) {
                    ds_info2.setCellData(row, "dptHh", "0" + (Ahr + 1) + AMn);
                    if (prevRowObj.arvDt > rowObj.dptDt) {
                        ds_info2.setCellData(row, "dptDt", DdtYMD);
                    }
                } else {
                    ds_info2.setCellData(row, "dptHh", (Ahr + 1) + AMn);
                    if (prevRowObj.arvDt > rowObj.dptDt) {
                        ds_info2.setCellData(row, "dptDt", DdtYMD);
                    }
                }
            } else {
                let param1 = $c.date.addDate(DdtYMD, 1);
                ds_info2.setCellData(row, "dptDt", param1);
                ds_info2.setCellData(row, "dtpHh", "00" + AMn);
            }
        }
    }
    //위에서 값 변경해서 새로고침
    rowObj = ds_info2.getRowJSON(row);

    if (scwin.f_checkColValue(row, rowObj, "arvHh")) {
        if (avr == "" || isNaN(avr)) {
            scwin.fillArvDthhCell(row, rowObj);
        }
    }
};


scwin.f_applyDel = function () {
    for (var row = ds_emp2.getRowCount() - 1; row >= 0; row--) {
        let Dhr = parseInt(ds_emp2.getCellData(row, "dptHh").substr(0, 2), 10);
        let Ahr = parseInt(ds_emp2.getCellData(row, "arvHh").substr(0, 2), 10);

        //출발일시/도착일시가 있는경우만 진행하기
        if (!isNaN(Dhr) && !isNaN(Ahr)) {
            ds_emp2.setCellData(row, "dptHh", "");
            ds_emp2.setCellData(row, "arvHh", "");
        }
    }
};

scwin.sbm_retrieve_submitdone = function (e) {
    let rowCnt = ds_emp.getRowCount();
    if (rowCnt == 0) {
        ds_emp2.removeAll();
        $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);
    }
    // cfGoPrevPosition 호환 로직
    if (scwin.pos_groupCode > -1 && scwin.pos_groupCode < rowCnt) {
        ds_emp.setRowPosition(scwin.pos_groupCode);
    }
    scwin.g_chkScroll = true;
};

scwin.sbm_retrieve2_submitdone = function (e) {
    let rowCnt = ds_emp2.getRowCount();
    if (rowCnt == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);
    }
    totalRows.setValue(rowCnt);

    // 조건에 따른 그리드 컬럼 숨기기/보이기
    for (let i = 0; i < rowCnt; i++) {
        if (ds_emp2.getCellData(i, "repClntNo") == "000012" && ds_emp2.getCellData(i, "steelVehclYn") == 1 && ds_emp2.getCellData(i, "realPdaYn") == 0) {
            // 웹스퀘어는 컬럼 단위 속성 변경 시 setColumnVisible 등을 사용
            gr_emp2.setColumnVisible("allocInput", true);
        } else {
            gr_emp2.setColumnVisible("allocInput", false);
        }
    }
};

scwin.sbm_saveEmp_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다.
    scwin.f_Retrieve2();
};

//===========================================================================
// [검증] 컬럼 편집 가능 여부 체크 (AS-IS: f_checkColValue)
//===========================================================================
scwin.f_checkColValue = function (row, colid) {
    let ds = ds_emp2;
    let gr = gr_emp2;

    switch (colid) {
        case "dptHh":
            // 1. 컨테이너 번호 및 출발일자 체크
            if (ds.getCellData(row, "cntrNo") == "") {
                ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                gr.setColumnReadOnly(colid, true); // Edit = None 효과
                return false;
            }
            if (ds.getCellData(row, "dptDt") == "") {
                ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                gr.setColumnReadOnly(colid, true);
                return false;
            }

            // 2. 출발 입출고 관리 대상이거나 컨테이너가 없는 경우
            if (ds.getCellData(row, "dptIoMgntYn") == "1" || ds.getCellData(row, "cntrNo") == "") {
                ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                gr.setColumnReadOnly(colid, true);
                return false;
            } else {
                // 3. 실복화 단계(realCmpstcrgYn == "2")인 경우 입력 불가
                if (ds.getCellData(row, "realCmpstcrgYn") == "2") {
                    ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                    gr.setColumnReadOnly(colid, true);
                    return false;
                }
                // 4. 특정 오더 종류 및 작업 단계 조건부 제어
                else if (ds.getCellData(row, "realCmpstcrgYn") == "1" &&
                    ds.getCellData(row, "odrKndCd") == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR &&
                    ds.getCellData(row, "wrkStpCd") == DsConstants.WRK_STP_CD_RETRV) {
                    gr.setColumnReadOnly(colid, true);
                    return false;
                } else {
                    gr.setColumnReadOnly(colid, false); // Edit = Any 효과
                }
            }

            // 5. 특정 작업장(DPCTCY, BPTCY)인 경우 수정 불가
            if (ds.getCellData(row, "dptWrkPlCd") == "6C09" || ds.getCellData(row, "dptWrkPlCd") == "6C01") {
                gr.setColumnReadOnly("dptHh", true);
                gr.setColumnReadOnly("dptDt", true);
                return false;
            }
            break;

        case "arvHh":
            // 1. 컨테이너 번호 유무 체크
            if (ds.getCellData(row, "cntrNo") == "") {
                ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                gr.setColumnReadOnly(colid, true);
                return false;
            }

            // 2. 출발 일시가 입력되지 않은 경우
            if (ds.getCellData(row, "dptDt") == "" || ds.getCellData(row, "dptHh") == "") {
                // 직도어 복화중 최초/최종 단계인 경우만 입력 가능
                if (ds.getCellData(row, "realCmpstcrgYn") == "1") {
                    gr.setColumnReadOnly(colid, false);
                } else if (ds.getCellData(row, "realCmpstcrgYn") == "2") {
                    gr.setColumnReadOnly(colid, true);
                    return false;
                } else {
                    ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                    gr.setColumnReadOnly(colid, true);
                    return false;
                }
            }

            // 3. 도착 일자 체크
            if (ds.getCellData(row, "arvIoMgntYn") == "0" && ds.getCellData(row, "arvDt") == "") {
                ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                gr.setColumnReadOnly(colid, true);
                return false;
            }

            // 4. 도착 입출고 관리 대상 여부
            if (ds.getCellData(row, "arvIoMgntYn") == "1" || ds.getCellData(row, "cntrNo") == "") {
                ds.setCellData(row, colid, ds.getOriginalCellData(row, colid));
                gr.setColumnReadOnly(colid, true);
                return false;
            } else {
                if (ds.getCellData(row, "realCmpstcrgYn") == "2") {
                    gr.setColumnReadOnly(colid, true);
                    return false;
                } else {
                    gr.setColumnReadOnly(colid, false);
                }
            }

            // 5. 특정 도착 작업장 수정 불가
            if (ds.getCellData(row, "arvWrkPlCd") == "6C09" || ds.getCellData(row, "arvWrkPlCd") == "6C01") {
                gr.setColumnReadOnly("arvHh", true);
                gr.setColumnReadOnly("arvDt", true);
                return false;
            }
            break;
    }

    return true;
};

