scwin.hourCheck = function () {
    for (let i = 0; i < ds_emp2.getRowCount(); i++) {
        // 기존의 cf_gidHourCheck 대신 웹스퀘어 공통함수 또는 정규식 사용
        if (!dscommon.cf_gidHourCheck(ds_emp2.getCellData(i, "dptHh"))) {
            ds_emp2.setRowPosition(i);
            $c.win.alert((i + 1) + "번째 출발시간을 정확한 시간을 입력하세요");
            gr_emp2.setFocusedCell(i, "dptHh", true);
            return false;
        }
    }
    return true;
};

scwin.hourNullCheck = function () {
    for (let i = 0; i < ds_emp2.getRowCount(); i++) {
        if (!dscommon.cf_gidHourNullCheck(ds_emp2.getCellData(i, "arvHh"))) {
            ds_emp2.setRowPosition(i);
            $c.win.alert((i + 1) + "번째 도착시간을 정확한 시간을 입력하세요");
            gr_emp2.setFocusedCell(i, "arvHh", true);
            return false;
        }
        if (ds_emp2.getCellData(i, "arvHh") == "") {
            ds_emp2.setCellData(i, "arvDt", "");
        }
    }
    return true;
};

scwin.f_DifferBetweenDate = function (sDateStr, eDateStr) {
    sDateStr = sDateStr.trim();
    eDateStr = eDateStr.trim();
    if (eDateStr == "00" || sDateStr == "00") return true;
    if (sDateStr >= eDateStr) return false;
    return true;
};

scwin.f_validDate = function (sDateStr, dateFormat, msg) {
    sDateStr = sDateStr.trim();
    if (dateFormat == null) dateFormat = "YYYYMMDD";

    // AS-IS: covDateValidator. 웹스퀘어 공통 함수로 치환 
    if (!$c.date.isDate(sDateStr)) {
        $c.gus.cfAlertMsg(msg + " 입력이 잘못 되었습니다.");
        return false;
    }
    return true;
};


scwin.gr_emp2_onviewchange = function (info) {
    let row = info.rowIndex;
    let colid = info.colID;

    let rowEmp = ds_emp.getRowPosition();
    let tot = 0;

    if (row > -1 && ds_emp2.getRowCount() > row) {
        if (colid == "rglWrkWt") {
            for (let i = 0; i <= row; i++) {
                tot += Number(ds_emp2.getCellData(i, colid));
            }
            if (tot > Number(ds_emp.getCellData(rowEmp, "rglWrkWt"))) {
                if (confirm("과적입니다. 그래도 계속 하시겠습니까.") != true) {
                    ds_emp2.undoRow(row);
                }
            }
        }
    }

    switch (colid) {
        case "dptDt":
        case "dptHh":
        case "arvDt":
        case "arvHh":
            let curShippingNo = ds_emp2.getCellData(row, "coshippingNo");
            for (let j = 0; j < ds_emp2.getRowCount(); j++) {
                if (ds_emp2.getCellData(j, "coshippingNo") == curShippingNo && curShippingNo != "") {
                    ds_emp2.setCellData(j, colid, ds_emp2.getCellData(row, colid));
                }
            }
            break;
    }
};
