};

scwin.btnUndoMark_onclick = function (e) {
    let chkArr = ds_emp2.getMatchedIndex("che", "1"); 
    for (let i = chkArr.length - 1; i >= 0; i--) {
        ds_emp2.undoRow(chkArr[i]);
    }
};

