scwin.f_chkOpenCommonPopUpText = function (inObj, codeObj, disGubun) {
    let pCode = "";
    let pName = "";

    if (inObj.getReadOnly() || (inObj.getValue() == inObj.options?.hidVal)) return;

    if (codeObj != null) {
        codeObj.setValue("");
        if (codeObj.options) codeObj.options.hidVal = "";
    }

    pName = inObj.getValue();
    scwin.f_openPopUp(disGubun, pCode, pName, 'T', 'T');
};
