//===========================================================================
// [기능] 행추가 시 디폴트값 셋팅 (AS-IS: NewAddRow)
//===========================================================================
scwin.NewAddRow = function () {
    let row = ds_emp2.getRowPosition();

    if (ds_emp2.getCellData(row, "ioDptWrkPlCd") == "1") {
        $c.win.alert("입출고 관리 대상이므로 추가 못합니다.");
        return;
    }

    if (row > -1) {
        let newRow = ds_emp2.insertRow(ds_emp2.getRowCount());

        // 이전 행의 데이터를 그대로 복사하여 디폴트값으로 세팅
        let colsToCopy = [
            "transWrkIndictNo", "transRsltsSeq", "wrkStpNm", "dptWrkPlCdNm", "arvWrkPlCdNm",
            "commCd", "commCdNm", "odrNo", "ctrtNo", "ctrtClntNo", "commSeq", "eqCd",
            "wrkPathSeq", "wrkStpSeq", "copCoClntNo", "grossWt", "netWt", "unitCd",
            "wrkUnitCd", "eqKndCd", "eqNrmCd", "wrkLobranCd", "internalSellLodeptCd",
            "vehclNo", "dptWrkPlCd", "arvWrkPlCd", "pchsSeq", "coShippingType",
            "minimumAdptYn", "paletAdptYn", "coshippingNo"
        ];

        colsToCopy.forEach(col => {
            ds_emp2.setCellData(newRow, col, ds_emp2.getCellData(row, col));
        });

        ds_emp2.setRowPosition(newRow);
        gr_emp2.setFocusedCell(newRow, "dptDt", true);
    } else {
        $c.win.alert("조회된 데이타가 없습니다.");
    }
};

