//===========================================================================
// [기능] 그리드 삭제 버튼 (AS-IS: f_Del)
//===========================================================================
scwin.f_Del = function () {
    let row = ds_emp2.getRowPosition();
    if (row < 0) return;

    let coshippingNo = ds_emp2.getCellData(row, "coshippingNo");

    if (coshippingNo != "") {
        // coshippingNo가 같은 연관 데이터 일괄 삭제
        let delIdxArr = [];
        for (let j = 0; j < ds_emp2.getRowCount(); j++) {
            if (ds_emp2.getCellData(j, "coshippingNo") == coshippingNo) {
                delIdxArr.push(j);
            }
        }
        if (delIdxArr.length > 0) ds_emp2.removeRows(delIdxArr);
    } else {
        ds_emp2.removeRow(row);
    }
};

//===========================================================================
// [이벤트] 그리드 더블클릭 (AS-IS: gr_emp2 OnDblClick) - 이동경로 및 팝업 처리
//===========================================================================
scwin.gr_emp2_oncelldblclick = function (row, col) {
    let stDtm = ds_emp2.getCellData(row, "dptDt").trim();
    let endDtm = ds_emp2.getCellData(row, "arvDt").trim();
    let aaa = stDtm.substring(0, 8);
    let bbb = endDtm.substring(0, 8);
    let colId = gr_emp2.getColumnID(col);
    let diffDays = $c.date.diffDate(aaa, bbb);

    if (diffDays > 4) {
        $c.win.alert("7일 이상의 기간은   경로생성이 안됩니다");
        return;
    }
    if (ds_emp2.getCellData(row, "dptHh") != "" || ds_emp2.getCellData(row, "arvHh") != "") {
        if (colId == "allocInput") {
            if (ds_emp2.getCellData(row, "repClntNo") == "000012" && ds_emp2.getCellData(row, "steelVehclYn") == "1" && ds_emp2.getCellData(row, "realPdaYn") == "0") {
                if (ds_emp2.getCellData(row, "dptXPos") == "" || ds_emp2.getCellData(row, "dptYPos") == "") {

                    let paramData = {
                        "WRKPLCD": ds_emp2.getCellData(row, "dptWrkPlCd"),
                        "WRKPLCDNM": ds_emp2.getCellData(row, "dptWkrPlCdNm"),
                        "HDOFFICEIDX": ds_emp2.getCellData(row, "dptHdofficeIdx"),
                        "BHOFFICEIDX": ds_emp2.getCellData(row, "dptBhofficeIdx"),
                        "OFFICEIDX": ds_emp2.getCellData(row, "dptOfficeIdx"),
                        "EZ112IDX": ds_emp2.getCellData(row, "dptEz112Idx")
                    };

                    if (row > -1) {
                        let options = { id: "op_304_01_02p", type: "wframePopup", width: "700px", height: "700px", popupName: "작업장입력" };
                        $c.win.openPopup("/ui/op/304/op_304_01_02p.xml", options, paramData);
                    }
                } else if (ds_emp2.getCellData(row, "arvXPos") == "" || ds_emp2.getCellData(row, "arvYPos") == "") {

                    let paramData = {
                        "WRKPLCD": ds_emp2.getCellData(row, "arvWrkPlCd"),
                        "WRKPLCDNM": ds_emp2.getCellData(row, "arvWrkPlCdNm"),
                        "HDOFFICEIDX": ds_emp2.getCellData(row, "arvHdofficeIdx"),
                        "BHOFFICEIDX": ds_emp2.getCellData(row, "arvBhofficeIdx"),
                        "OFFICEIDX": ds_emp2.getCellData(row, "arvOfficeIdx"),
                        "EZ112IDX": ds_emp2.getCellData(row, "arvEz112Idx")
                    }; op_304_01_02p

                    if (row > -1) {
                        let options = { id: "op_304_01_02p", type: "wframePopup", width: "700px", height: "700px", popupName: "작업장입력" };
                        $c.win.openPopup("/ui/op/304/op_304_01_02p.xml", options, paramData);
                    }
                } else {
                    if (ds_emp2.getCellData(row, "pdaNo") == "") {
                        $c.win.alert("PDA번호가 없습니다");
                        return false;
                    } else {
                        ds_CreateLocation.removeAll();
                        let newRow = ds_CreateLocation.insertRow(0);

                        ds_CreateLocation.setCellData(newRow, "fromXPos", ds_emp2.getCellData(row, "dptXPos"));
                        ds_CreateLocation.setCellData(newRow, "fromYPos", ds_emp2.getCellData(row, "dptYPos"));
                        ds_CreateLocation.setCellData(newRow, "toXPos", ds_emp2.getCellData(row, "arvXPos"));
                        ds_CreateLocation.setCellData(newRow, "toYPos", ds_emp2.getCellData(row, "arvYPos"));
                        ds_CreateLocation.setCellData(newRow, "dptDt", ds_emp2.getCellData(row, "dptDt"));
                        ds_CreateLocation.setCellData(newRow, "dptHh", ds_emp2.getCellData(row, "dptHh"));
                        ds_CreateLocation.setCellData(newRow, "arvDt", ds_emp2.getCellData(row, "arvDt"));
                        ds_CreateLocation.setCellData(newRow, "arvHh", ds_emp2.getCellData(row, "arvHh"));
                        ds_CreateLocation.setCellData(newRow, "vehclNo", ds_emp2.getCellData(row, "vehclNo"));
                        ds_CreateLocation.setCellData(newRow, "pdaNo", ds_emp2.getCellData(row, "pdaNo"));
                        ds_CreateLocation.setCellData(newRow, "picNm", ds_emp2.getCellData(row, "picNm"));
                        ds_CreateLocation.setCellData(newRow, "handphoneNo", ds_emp2.getCellData(row, "handphoneNo"));

                        $c.sbm.execute(sbm_CreateLocation);
                    }
                }
            } else {
                $c.win.alert("위치입력 대상이 아닙니다");
            }
        }
    } else {
        $c.win.alert("출도착 보고 후 사용 가능합니다.");
    }
};

//===========================================================================
// [기능] 위치 정보 저장 (AS-IS: f_save2)
//===========================================================================
scwin.f_save2 = function () {
    let rowCnt = ds_Trace.getRowCount();
    if (rowCnt > 0 && ds_Trace.getCellData(rowCnt - 1, "gpsNo").trim() == "") {
        $c.win.alert("해당 차량의 스마트폰 번호가 입력되지 않았습니다.");
        return false;
    }

    for (let i = 0; i < rowCnt; i++) {
        if ($c.gus.cfIsNull(ds_Trace.getCellData(i, "rcvDt").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["추적일"]);
            return false;
        }
        if ($c.gus.cfIsNull(ds_Trace.getCellData(i, "rcvHh").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["추적시간"]);
            return false;
        }
        if ($c.gus.cfIsNull(ds_Trace.getCellData(i, "spd").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["속도"]);
            return false;
        }
        if ($c.gus.cfIsNull(ds_Trace.getCellData(i, "province").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["도"]);
            return false;
        }
        if ($c.gus.cfIsNull(ds_Trace.getCellData(i, "gu").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["구"]);
            return false;
        }
        if ($c.gus.cfIsNull(ds_Trace.getCellData(i, "dong").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["동"]);
            return false;
        }
    }

    $c.sbm.execute(sbm_SaveTrackingInformation);
    $c.win.alert("위치저장종료");
};

