scwin.gr_emp2_onviewchange = function(info) {
    debugger;
    let colId = gr_emp2.getColumnID(info.colIndex);

    if (colId === "rglWrkWt" || colId === "rglWrkCubic" || colId === "badWrkWt" || colId === "badWrkCubic") { 
        let val = String(info.newValue);

        if (val.indexOf(".") > -1) {
            let parts = val.split(".");

            if (parts[1].length > 3) {
                let cutText = parts[0] + "." + parts[1].substring(0, 3);


                ds_emp2.setCellData(info.rowIndex, info.colId, cutText);
            }
        }
    }
};
